```python
import pandas as pd

# Load the CSV
df = pd.read_csv('data/users_export.csv')

# Backup the original file
df_backup = df.copy()
df_backup.to_csv('data/users_export_backup.csv', index=False)

# Keep the most recent record for each ID
df = df.sort_values('created_at').drop_duplicates(subset='id', keep='last')

# Merge incomplete records into a single record with a note
incomplete_ids = df[df['name'].isna() | df['email'].isna()].index
for idx in incomplete_ids:
    incomplete_row = df.loc[idx]
    merged_row = df[df['id'] == incomplete_row['id']].iloc[0]
    merged_row['note'] = f"Incomplete record: {incomplete_row.to_dict()}"
    df = df.drop(idx).append(merged_row, ignore_index=True)

# Save the cleaned CSV
df.to_csv('data/users_export_cleaned.csv', index=False)

print("Cleanup complete. Backup saved as data/users_export_backup.csv. Cleaned file saved as data/users_export_cleaned.csv.")
```

